export function parseRetryAfter(value, nowMs) {
  const text = String(value).trim();
  if (/^\d+$/.test(text)) return Number(text);
  const target = Date.parse(text);
  if (Number.isNaN(target)) return null;
  return Math.max(0, target - nowMs);
}

