export class RetryBudget {
  constructor(limitMs) {
    this.limitMs = limitMs;
    this.usedMs = 0;
  }

  claim(requestedMs) {
    if (requestedMs < 0 || this.usedMs + requestedMs > this.limitMs) {
      return null;
    }
    this.usedMs += requestedMs;
    return requestedMs;
  }
}

