import { parseRetryAfter } from "./retry_after.mjs";

export function scheduleRetry({ retryAfter, nowMs, budget, enqueue }) {
  const requestedMs = parseRetryAfter(retryAfter, nowMs);
  if (requestedMs === null) return null;
  const grantedMs = budget.claim(requestedMs);
  if (!grantedMs) return null;
  const runAt = nowMs + requestedMs;
  enqueue(runAt);
  return runAt;
}

