import test from "node:test";
import assert from "node:assert/strict";
import { RetryBudget } from "../src/budget.mjs";
import { scheduleRetry } from "../src/scheduler.mjs";

test("an HTTP-date delay within budget is queued", () => {
  const nowMs = 1_700_000_000_000;
  const queued = [];
  const runAt = scheduleRetry({
    retryAfter: new Date(nowMs + 4_000).toUTCString(),
    nowMs,
    budget: new RetryBudget(5_000),
    enqueue: (time) => queued.push(time),
  });

  assert.equal(runAt, nowMs + 4_000);
  assert.deepEqual(queued, [nowMs + 4_000]);
});
